function forEvents(e,t){e.split(/\s+/).forEach(e=>{t(e)})}class MicroEvent{constructor(){this._events={}}on(e,t){forEvents(e,e=>{this._events[e]=this._events[e]||[],this._events[e].push(t)})}off(e,t){var s=arguments.length;0!==s?forEvents(e,e=>{if(1===s)return delete this._events[e];e in this._events!=!1&&this._events[e].splice(this._events[e].indexOf(t),1)}):this._events={}}trigger(e,...t){var s=this;forEvents(e,e=>{if(e in s._events!=!1)for(let n of s._events[e])n.apply(s,t)})}}export default MicroEvent;